const BUNDLE_ID = "phase-spider-cr-plus-one-fixed";
const ACTOR_HINTS = ["фазовый паук", "phase spider"];

const AMBUSH_MACRO = `const data = args?.[0] ?? {};
if (data.macroPass !== "postActiveEffects") return;
const selfActor = actor ?? data.workflow?.actor;
if (!selfActor) return;
const old = selfActor.effects.filter(e => e.getFlag("ai-patcher", "phaseSpiderAmbush"));
if (old.length) await selfActor.deleteEmbeddedDocuments("ActiveEffect", old.map(e => e.id));
await selfActor.createEmbeddedDocuments("ActiveEffect", [{
  name: "Фазовая засада",
  icon: "icons/magic/movement/trail-streak-zigzag-teal.webp",
  origin: item?.uuid,
  duration: { rounds: 1, turns: 1 },
  changes: [],
  flags: {
    "ai-patcher": { phaseSpiderAmbush: true, bundleId: "${BUNDLE_ID}" },
    dae: { specialDuration: ["1Attack", "turnEndSource"] }
  }
}]);
await ChatMessage.create({
  speaker: ChatMessage.getSpeaker({ actor: selfActor, token: token?.document ?? token }),
  content: "<p><strong>Фазовая засада.</strong> Следующий Укус из Междумирья наносит дополнительно <strong>2d8 урона силовым полем</strong>.</p>"
});`;

const BITE_MACRO = `const data = args?.[0] ?? {};
const workflow = data.workflow;
const selfActor = actor ?? workflow?.actor;
if (!selfActor) return;
if (data.macroPass === "DamageBonus") {
  const ambush = selfActor.effects.find(e => e.getFlag("ai-patcher", "phaseSpiderAmbush"));
  if (!ambush) return {};
  await ambush.delete();
  return { damageRoll: "2d8[force]", flavor: "Фазовая засада: удар из Эфира" };
}
if (data.macroPass !== "postActiveEffects") return;
const targets = Array.from(workflow?.hitTargets ?? []);
for (const target of targets) {
  const targetActor = target?.actor;
  if (!targetActor) continue;
  const old = targetActor.effects.filter(e => e.getFlag("ai-patcher", "phaseSpiderMark"));
  if (old.length) await targetActor.deleteEmbeddedDocuments("ActiveEffect", old.map(e => e.id));
  await targetActor.createEmbeddedDocuments("ActiveEffect", [{
    name: "Фазовая метка",
    icon: "icons/magic/movement/portal-vortex-ring-blue.webp",
    origin: item?.uuid,
    duration: { rounds: 2 },
    changes: [],
    flags: { "ai-patcher": { phaseSpiderMark: true, bundleId: "${BUNDLE_ID}" } }
  }]);
}
if (targets.length) {
  await ChatMessage.create({
    speaker: ChatMessage.getSpeaker({ actor: selfActor, token: token?.document ?? token }),
    content: "<p><strong>Фазовая метка.</strong> Попавшая цель отмечена и может быть разорвана Разрывом фазовой метки.</p>"
  });
}`;

const COCOON_MACRO = `const data = args?.[0] ?? {};
if (data.macroPass !== "postActiveEffects") return;
const workflow = data.workflow;
const failed = Array.from(workflow?.failedSaves ?? []);
for (const target of failed) {
  const targetActor = target?.actor;
  if (!targetActor) continue;
  const old = targetActor.effects.filter(e => e.getFlag("ai-patcher", "phaseSpiderCocoon"));
  if (old.length) await targetActor.deleteEmbeddedDocuments("ActiveEffect", old.map(e => e.id));
  await targetActor.createEmbeddedDocuments("ActiveEffect", [{
    name: "Эфирный кокон",
    icon: "icons/magic/control/debuff-chains-shackles-movement-blue.webp",
    origin: item?.uuid,
    duration: { rounds: 1, turns: 1 },
    statuses: ["restrained"],
    changes: [
      { key: "flags.midi-qol.fail.reaction.all", mode: CONST.ACTIVE_EFFECT_MODES.CUSTOM, value: "1", priority: 20 }
    ],
    flags: {
      "ai-patcher": { phaseSpiderCocoon: true, bundleId: "${BUNDLE_ID}" },
      dae: { specialDuration: ["turnEndSource"] }
    }
  }]);
}
if (failed.length) {
  await ChatMessage.create({
    speaker: ChatMessage.getSpeaker({ actor: actor ?? workflow?.actor, token: token?.document ?? token }),
    content: "<p><strong>Эфирный кокон.</strong> Провалившие спасбросок цели опутаны межплановой паутиной, удержаны и не могут совершать реакции.</p>"
  });
}`;

const RIFT_MACRO = `const data = args?.[0] ?? {};
if (data.macroPass !== "postActiveEffects") return;
const selfActor = actor ?? data.workflow?.actor;
const marked = canvas?.tokens?.placeables?.filter(t => t.actor?.effects?.some(e => e.getFlag("ai-patcher", "phaseSpiderMark"))) ?? [];
if (!marked.length) {
  ui.notifications?.warn("Разрыв фазовой метки: на сцене нет целей с Фазовой меткой.");
  return;
}
const roll = await new Roll("2d8[force]").evaluate();
await roll.toMessage({
  speaker: ChatMessage.getSpeaker({ actor: selfActor, token: token?.document ?? token }),
  flavor: "<strong>Разрыв фазовой метки</strong>: урон всем отмеченным целям"
});
if (game.modules.get("midi-qol")?.active && MidiQOL?.applyTokenDamage) {
  await MidiQOL.applyTokenDamage(
    [{ damage: roll.total, type: "force" }],
    roll.total,
    new Set(marked),
    item,
    new Set(marked),
    { flavor: "Разрыв фазовой метки", itemCardId: data.workflow?.itemCardId }
  );
} else {
  for (const target of marked) {
    const hp = target.actor?.system?.attributes?.hp;
    if (!hp) continue;
    await target.actor.update({ "system.attributes.hp.value": Math.max(0, Number(hp.value ?? 0) - roll.total) });
  }
}
for (const target of marked) {
  const marks = target.actor?.effects?.filter(e => e.getFlag("ai-patcher", "phaseSpiderMark")) ?? [];
  if (marks.length) await target.actor.deleteEmbeddedDocuments("ActiveEffect", marks.map(e => e.id));
}
await ChatMessage.create({
  speaker: ChatMessage.getSpeaker({ actor: selfActor, token: token?.document ?? token }),
  content: \`<p><strong>Разрыв фазовой метки.</strong> Автоматически поражено целей: <strong>\${marked.length}</strong>. Фазовые метки сняты.</p>\`
});`;

const VOID_STEP_MACRO = `const data = args?.[0] ?? {};
if (data.macroPass !== "postActiveEffects") return;
const selfActor = actor ?? data.workflow?.actor;
if (!selfActor) return;
const old = selfActor.effects.filter(e => e.getFlag("ai-patcher", "phaseSpiderVoidStep"));
if (old.length) await selfActor.deleteEmbeddedDocuments("ActiveEffect", old.map(e => e.id));
await selfActor.createEmbeddedDocuments("ActiveEffect", [{
  name: "Провал в Эфир",
  icon: "icons/magic/defensive/illusion-evasion-echo-purple.webp",
  origin: item?.uuid,
  duration: { rounds: 1, turns: 1 },
  changes: [
    { key: "system.attributes.ac.bonus", mode: CONST.ACTIVE_EFFECT_MODES.ADD, value: "3", priority: 20 }
  ],
  flags: {
    "ai-patcher": { phaseSpiderVoidStep: true, bundleId: "${BUNDLE_ID}" },
    dae: { specialDuration: ["isAttacked", "turnEndSource"] }
  }
}]);
await ChatMessage.create({
  speaker: ChatMessage.getSpeaker({ actor: selfActor, token: token?.document ?? token }),
  content: "<p><strong>Провал в Эфир.</strong> Паук получает +3 к КД против следующей атаки и смещается в дрожащую прослойку Эфира.</p>"
});`;

function activityValues(activities) {
  if (!activities) return [];
  if (activities.contents) return activities.contents;
  if (activities.values) return Array.from(activities.values());
  return Object.values(activities);
}

function clone(data) {
  return foundry.utils.deepClone(data);
}

function macroFlags(name, command, passes) {
  return {
    itemacro: {
      macro: {
        name,
        type: "script",
        command,
        author: game.user.id,
        scope: "global"
      }
    },
    "midi-qol": {
      onUseMacroName: `${name},${passes}`
    },
    dae: {
      macro: {
        name,
        type: "script",
        command,
        img: "icons/svg/dice-target.svg"
      }
    }
  };
}

function findPhaseSpider() {
  const candidates = game.actors.filter((actor) => {
    const name = String(actor.name ?? "").toLowerCase();
    return actor.type === "npc" && ACTOR_HINTS.some((hint) => name.includes(hint));
  });
  candidates.sort((a, b) => {
    const exactA = ACTOR_HINTS.includes(String(a.name ?? "").toLowerCase()) ? 0 : 1;
    const exactB = ACTOR_HINTS.includes(String(b.name ?? "").toLowerCase()) ? 0 : 1;
    return exactA - exactB || a.name.localeCompare(b.name);
  });
  return candidates[0];
}

function saveDc(actor) {
  const dex = Number(actor.system?.abilities?.dex?.mod ?? Math.floor((Number(actor.system?.abilities?.dex?.value ?? 16) - 10) / 2));
  const prof = Number(actor.system?.attributes?.prof ?? 2);
  return Math.max(15, 8 + prof + dex);
}

function baseItem(name, img, description) {
  return {
    name,
    type: "feat",
    img,
    system: {
      description: { value: description, chat: "" },
      source: { revision: 1, rules: "2024", custom: "AI Patcher" },
      uses: { spent: 0, recovery: [], max: "" },
      activities: {},
      type: { value: "monster", subtype: "" },
      properties: []
    },
    effects: [],
    flags: {
      "ai-patcher": { bundleId: BUNDLE_ID, phaseSpiderUpgrade: true },
      world: { phaseSpiderCRPlusOne: true }
    },
    ownership: { default: 0, [game.user.id]: 3 }
  };
}

function setActivityName(item, name) {
  const activity = activityValues(item.system.activities)[0];
  if (activity) activity.name = name;
  return activity;
}

function addAttackActivity(item, { activityName, activation = "action", range = 5, ability = "dex", damageParts = [] }) {
  const source = clone(item);
  source.system.actionType = "mwak";
  source.system.activation = { type: activation, cost: 1, condition: "" };
  source.system.attack = { bonus: "", flat: false };
  source.system.ability = ability;
  source.system.range = { value: null, long: null, reach: range, units: "ft" };
  source.system.target = { value: 1, type: "creature", units: "", prompt: true };
  source.system.damage = { parts: damageParts };
  CONFIG.DND5E.activityTypes.attack.documentClass.createInitialActivity(source, { offset: 0 });
  item.system.activities = source.system.activities;
  setActivityName(item, activityName);
}

function addSaveActivity(item, { activityName, activation = "action", range = 60, ability = "dex", dc = 15, damageParts = [] }) {
  const source = clone(item);
  source.system.actionType = "save";
  source.system.activation = { type: activation, cost: 1, condition: "" };
  source.system.range = { value: range, units: "ft" };
  source.system.target = { value: 1, type: "creature", units: "", prompt: true };
  source.system.save = { ability, dc, scaling: "flat" };
  source.system.damage = { parts: damageParts };
  CONFIG.DND5E.activityTypes.save.documentClass.createInitialActivity(source, { offset: 0 });
  item.system.activities = source.system.activities;
  setActivityName(item, activityName);
}

function addDamageActivity(item, { activityName, activation = "action", range = 60, damageParts = [] }) {
  const source = clone(item);
  source.system.actionType = "other";
  source.system.activation = { type: activation, cost: 1, condition: "" };
  source.system.range = { value: range, units: "ft" };
  source.system.target = { value: null, type: "creature", units: "", prompt: false };
  source.system.damage = { parts: damageParts };
  CONFIG.DND5E.activityTypes.damage.documentClass.createInitialActivity(source, { offset: 0 });
  item.system.activities = source.system.activities;
  setActivityName(item, activityName);
}

function addUtilityActivity(item, { activityName, activation = "action" }) {
  const source = clone(item);
  source.system.activation = { type: activation, cost: 1, condition: "" };
  CONFIG.DND5E.activityTypes.utility.documentClass.createInitialActivity(source, { offset: 0 });
  item.system.activities = source.system.activities;
  setActivityName(item, activityName);
}

function buildItems(actor) {
  const dc = saveDc(actor);
  const items = [];

  const ambush = baseItem(
    "Фазовая засада",
    "icons/magic/movement/trail-streak-zigzag-teal.webp",
    "<p><strong>Бонусное действие.</strong> Паук исчезает в дрожащей прослойке Эфира. Следующий <strong>Укус из Междумирья</strong> до конца его следующего хода наносит дополнительно 2d8 урона силовым полем.</p>"
  );
  addUtilityActivity(ambush, { activityName: "Фазовая засада", activation: "bonus" });
  ambush.flags = { ...ambush.flags, ...macroFlags("Фазовая засада ItemMacro", AMBUSH_MACRO, "[postActiveEffects]ItemMacro") };
  items.push(ambush);

  const bite = baseItem(
    "Укус из Междумирья",
    "icons/creatures/abilities/fang-tooth-poison-green.webp",
    "<p><strong>Рукопашная атака оружием.</strong> При попадании цель получает колющий и ядовитый урон, а также <strong>Фазовую метку</strong> на 2 раунда. Если активна Фазовая засада, укус дополнительно наносит 2d8 урона силовым полем.</p>"
  );
  addAttackActivity(bite, { activityName: "Укус из Междумирья", activation: "action", range: 5, damageParts: [["1d10 + 4", "piercing"], ["3d8", "poison"]] });
  bite.flags = { ...bite.flags, ...macroFlags("Укус из Междумирья ItemMacro", BITE_MACRO, "[DamageBonus]ItemMacro,[postActiveEffects]ItemMacro") };
  items.push(bite);

  const cocoon = baseItem(
    "Эфирный кокон (перезарядка 5-6)",
    "icons/magic/control/debuff-chains-shackles-movement-blue.webp",
    `<p><strong>Перезарядка 5-6.</strong> Одна цель в 60 фт совершает спасбросок Ловкости СЛ ${dc}. При провале межплановая паутина удерживает её до конца следующего хода паука: цель получает состояние <strong>удержан</strong> и не может совершать реакции.</p>`
  );
  cocoon.system.uses = { max: "1", spent: 0, recovery: [{ period: "recharge", formula: "5", type: "recoverAll" }] };
  addSaveActivity(cocoon, { activityName: "Эфирный кокон", activation: "action", range: 60, ability: "dex", dc });
  cocoon.flags = { ...cocoon.flags, ...macroFlags("Эфирный кокон ItemMacro", COCOON_MACRO, "[postActiveEffects]ItemMacro") };
  items.push(cocoon);

  const rift = baseItem(
    "Разрыв фазовой метки",
    "icons/magic/movement/portal-vortex-ring-blue.webp",
    "<p><strong>Действие.</strong> Паук разрывает все свои Фазовые метки на сцене. Макрос сам находит все отмеченные токены, наносит им 2d8 урона силовым полем через Midi-QOL и снимает метки. Ручной выбор целей не нужен.</p>"
  );
  addUtilityActivity(rift, { activityName: "Разрыв фазовой метки", activation: "action" });
  rift.flags = { ...rift.flags, ...macroFlags("Разрыв фазовой метки ItemMacro", RIFT_MACRO, "[postActiveEffects]ItemMacro") };
  items.push(rift);

  const voidStep = baseItem(
    "Провал в Эфир",
    "icons/magic/defensive/illusion-evasion-echo-purple.webp",
    "<p><strong>Реакция.</strong> Когда паук становится целью атаки, он смещается в Эфир и получает +3 к КД против следующей атаки. Эффект снимается после атаки или в конце следующего хода паука.</p>"
  );
  addUtilityActivity(voidStep, { activityName: "Провал в Эфир", activation: "reaction" });
  voidStep.flags = { ...voidStep.flags, ...macroFlags("Провал в Эфир ItemMacro", VOID_STEP_MACRO, "[postActiveEffects]ItemMacro") };
  items.push(voidStep);

  return items;
}

function upgradedBiography(actor) {
  const current = String(actor.system?.details?.biography?.value ?? "");
  const note = "<section class=\"ai-patcher-note\"><h2>Усиление AI Patcher: Фазовый паук +1 CR</h2><p>Паук научился использовать следы собственного фазового перехода как охотничью систему: он помечает добычу укусом, стягивает её эфирной паутиной и затем разрывает метки вспышкой из Междумирья.</p></section>";
  if (current.includes("Усиление AI Patcher: Фазовый паук +1 CR")) return current;
  return `${current}${note}`;
}

export default async function patch({ dryRun, log }) {
  if (game.system.id !== "dnd5e") throw new Error("Патч Фазового паука рассчитан на систему dnd5e.");

  const actor = findPhaseSpider();
  if (!actor) {
    throw new Error("Не найден актор с именем «Фазовый паук» или «Phase Spider» в текущем мире.");
  }

  const oldCr = Number(actor.system?.details?.cr ?? 0);
  const alreadyApplied = actor.getFlag("ai-patcher", "phaseSpiderCRPlusOneApplied") === true;
  const newCr = alreadyApplied ? oldCr : oldCr + 1;
  const itemData = buildItems(actor);
  const oldPatchItems = actor.items.filter((item) =>
    item.getFlag("ai-patcher", "bundleId") === BUNDLE_ID ||
    item.getFlag("ai-patcher", "phaseSpiderUpgrade") === true ||
    ["Фазовая засада", "Укус из Междумирья", "Эфирный кокон (перезарядка 5-6)", "Разрыв фазовой метки", "Провал в Эфир"].includes(item.name)
  );

  if (dryRun) {
    return {
      actor: actor.name,
      uuid: actor.uuid,
      currentCR: oldCr,
      newCR: newCr,
      portraitUntouched: actor.img,
      tokenUntouched: actor.prototypeToken?.texture?.src,
      deleteOldPatchItems: oldPatchItems.length,
      createItems: itemData.map((item) => item.name)
    };
  }

  log(`Усиление актора: ${actor.name}. CR ${oldCr} -> ${newCr}. Изображения не изменяются.`);

  if (oldPatchItems.length) {
    await actor.deleteEmbeddedDocuments("Item", oldPatchItems.map((item) => item.id));
  }

  await actor.update({
    "system.details.cr": newCr,
    "system.details.biography.value": upgradedBiography(actor),
    "flags.ai-patcher.phaseSpiderCRPlusOneApplied": true,
    "flags.ai-patcher.phaseSpiderOriginalCR": actor.getFlag("ai-patcher", "phaseSpiderOriginalCR") ?? oldCr,
    "flags.ai-patcher.phaseSpiderUpgradeBundleId": BUNDLE_ID
  });

  await actor.createEmbeddedDocuments("Item", itemData);

  return {
    actor: actor.uuid,
    name: actor.name,
    cr: actor.system.details.cr,
    addedItems: itemData.map((item) => item.name),
    portrait: actor.img,
    token: actor.prototypeToken?.texture?.src
  };
}
